  3→import { RPCHandler } from "@orpc/server/fetch";
  4→import * as schema from "@rudel/sql-schema";
  5→import { drizzle } from "drizzle-orm/d1";
  6→import { createAuth } from "./auth.js";
  7→import { getClickhouse } from "./clickhouse.js";
  8→import { ingestSession } from "./ingest.js";
  9→import { authMiddleware, os } from "./middleware.js";
 10→
 11→interface Env {
 12→	DB: D1Database;
 13→	APP_URL: string;
 14→	BETTER_AUTH_SECRET: string;
 15→	ALLOWED_ORIGIN: string;
 16→	TRUSTED_ORIGINS?: string;
 17→	GOOGLE_CLIENT_ID?: string;
 18→	GOOGLE_CLIENT_SECRET?: string;
 19→	GITHUB_CLIENT_ID?: string;
 20→	GITHUB_CLIENT_SECRET?: string;
 21→	CLICKHOUSE_URL: string;
 22→	CLICKHOUSE_USERNAME?: string;
 23→	CLICKHOUSE_PASSWORD?: string;
 24→}
