 15→function getCallbackURL(): string {
 16→	const params = new URLSearchParams(window.location.search);
 17→	const cliCallback = params.get("cli_callback");
 18→	const state = params.get("state");
 19→	if (cliCallback && state) {
 20→		return `/?cli_callback=${encodeURIComponent(cliCallback)}&state=${encodeURIComponent(state)}`;
 21→	}
 22→	return "/";
 23→}
