  1→import { afterAll, describe, expect, it, test } from "bun:test";
  2→import { createClickHouseExecutor } from "@chkit/clickhouse";
  3→import { ingestFlickClaudeSessions } from "../generated/chkit-ingest.js";
  4→import type { FlickClaudeSessionsRow } from "../generated/chkit-types.js";
  5→
  6→const testId = `test_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
  7→
  8→const baseExecutor = createClickHouseExecutor({
  9→	url: process.env.CLICKHOUSE_URL || "http://localhost:8123",
 10→	username:
 11→		process.env.CLICKHOUSE_USERNAME || process.env.CLICKHOUSE_USER || "default",
 12→	password: process.env.CLICKHOUSE_PASSWORD || "",
 13→	database: "default",
 14→});
