 75→describe("ingestFlickClaudeSessions", () => {
 76→	const now = new Date().toISOString().replace("Z", "");
 77→	const row: FlickClaudeSessionsRow = {
 78→		session_date: now,
 79→		last_interaction_date: now,
 80→		session_id: testId,
 81→		organization_id: "org_test",
 82→		project_path: "/test/project",
 83→		repository: null,
 84→		content: "test session content",
 85→		subagents: {},
 86→		skills: ["code:testing"],
 87→		slash_commands: [],
 88→		subagent_types: [],
 89→		ingested_at: now,
 90→		user_id: "user_test",
 91→		git_branch: "main",
 92→		git_sha: null,
 93→		input_tokens: "100",
