100→
101→	test("inserts a row and reads it back", async () => {
102→		const results = (await insertWithRetry(
103→			() => ingestFlickClaudeSessions(executor, [row]),
104→			() =>
105→				waitForQuery<{ session_id: string; tag: string }>(
106→					`SELECT session_id, tag FROM flick.claude_sessions WHERE session_id = '${testId}' LIMIT 1`,
107→				),
108→		)) as Array<{ session_id: string; tag: string }>;
109→
110→		expect(results).toHaveLength(1);
111→		expect(results[0]?.session_id).toBe(testId);
112→		expect(results[0]?.tag).toBe("integration-test");
113→	}, 120000);
